if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const body = $input.first().json.body || {};
const headers = $input.first().json.headers || {};
const auth = headers['x-gda-auth'] || headers['x-gda-key'] || body.auth_key || '';
const origin = (headers.origin || headers.referer || '').toLowerCase();
const trusted = ['gda.csr-llc.tech', 'n8n.csr-llc.tech', 'localhost'];
const fromTrusted = trusted.some(o => origin.includes(o));
if (auth !== $env.GDA_API_KEY_2026 && !fromTrusted) throw new Error('Unauthorized');
return $input.all();

