={{ (function() {
  var body = $('Auth Guard').first().json.body || {};
  var ctx = $('Load Live Context').first().json || {};

  var topPlans = '';
  try {
    var plans = typeof ctx.top_plans === 'string' ? JSON.parse(ctx.top_plans) : (ctx.top_plans || []);
    topPlans = plans.map(function(p) {
      var inc = p.incumbent && p.incumbent !== 'Unknown' && p.incumbent !== 'Unknown - Research Needed' ? p.incumbent : 'Unknown';
      var disc = '';
      try { disc = JSON.parse(p.discriminators||'[]').join('; '); } catch(e) { disc = p.discriminators||''; }
      return '- ' + p.opp_title + ' | ' + p.agency + ' | ' + (p.contract_value||'?') + ' | Stage: ' + (p.cap_stage||'?') + ' | PWin: ' + (p.pwin||'?') + '% | Incumbent: ' + inc + (disc ? ' | Discriminators: ' + disc : '');
    }).join('\n');
  } catch(e) { topPlans = 'unavailable'; }

  var deadlines = '';
  try {
    var dl = typeof ctx.upcoming_deadlines === 'string' ? JSON.parse(ctx.upcoming_deadlines) : (ctx.upcoming_deadlines || []);
    deadlines = dl.length ? dl.map(function(d) { return '- ' + d.opp_title + ' | ' + d.agency + ' | Due: ' + d.deadline; }).join('\n') : 'none';
  } catch(e) { deadlines = 'none'; }

  var incumbentBlock = '';
  try {
    var ki = typeof ctx.known_incumbents === 'string' ? JSON.parse(ctx.known_incumbents) : (ctx.known_incumbents || []);
    if (ki.length) {
      incumbentBlock = ki.map(function(i) { return '- ' + i.incumbent + ' (' + i.opp_count + ' opp' + (i.opp_count>1?'s':'') + '): ' + (Array.isArray(i.opportunities) ? i.opportunities.join(', ') : i.opportunities); }).join('\n');
    } else {
      incumbentBlock = 'No confirmed incumbents in active pipeline (84/95 marked Unknown — research needed)';
    }
  } catch(e) { incumbentBlock = 'unavailable'; }

  var winThemesBlock = '';
  try {
    var wt = typeof ctx.win_themes === 'string' ? JSON.parse(ctx.win_themes) : (ctx.win_themes || []);
    if (wt.length) {
      winThemesBlock = wt.map(function(w) {
        var disc = '';
        try { disc = JSON.parse(w.discriminators||'[]').join('; '); } catch(e) { disc = w.discriminators||''; }
        var str = '';
        try { str = JSON.parse(w.eis_strengths||'[]').join('; '); } catch(e) { str = w.eis_strengths||''; }
        return '- ' + w.opp_title + (disc ? '\n    Discriminators: ' + disc : '') + (str ? '\n    EIS Strengths: ' + str : '') + (w.win_strategy ? '\n    Strategy: ' + w.win_strategy.substring(0,200) : '');
      }).join('\n');
    } else {
      winThemesBlock = 'No win strategies on file';
    }
  } catch(e) { winThemesBlock = 'unavailable'; }

  var systemPrompt = 'You are the GDA Command AI Agent for Georgetown Defense Analytics (GDA), serving Shawn Seffernick, President of Envision Innovative Solutions. GDA consists of three operating units: Envision (Enable/OU3 — Training, Simulation, C5ISR), PD Systems (Train — Defense/Logistics), and Riverstone (Protect — Intelligence/Cyber/Zero Trust). Revenue target: $100M FY26. AOP: $42.8M.\n\nCore customers: TRADOC, PEO STRI, SOCOM, INSCOM, APG/C5ISR Center, CYBERCOM, DISA, MDA, FAA.\n\n=== LIVE PLATFORM DATA (real-time) ===\nActive pipeline: ' + (ctx.active_opps||'?') + ' opps | $' + (ctx.pipeline_m||'?') + 'M\nPursuing: ' + (ctx.pursue_count||'?') + ' opps | $' + (ctx.pursue_value_m||'?') + 'M\nActive capture plans: ' + (ctx.active_plans||'?') + '\nDeadlines in 30 days: ' + (ctx.deadlines_30d||0) + '\n\nTop capture plans (with incumbent + discriminators):\n' + (topPlans||'none') + '\n\nUpcoming deadlines:\n' + deadlines + '\n\n=== INCUMBENT INTELLIGENCE ===\n' + incumbentBlock + '\n\n=== WIN THEMES & DISCRIMINATORS (top active plans) ===\n' + winThemesBlock + '\n\n=== CAPABILITIES ===\n- 764+ semantic vectors (opps, capture plans, deep research, contracts)\n- 4 deep research reports: Leidos, SAIC, Booz Allen, TRADOC\n- Active contracts: $235.7M ceiling across 5 contracts\n- 35+ competitor profiles\n\nBe concise, strategic, actionable. Use live data above to answer questions. If asked about documents, perform thorough analysis covering compliance, win probability, strengths, weaknesses, and recommendations.\n\nMatch Shawn\'s terse directive style. Direct answers, no pleasantries.';

  var userContent = (body.rfp_text ? 'RED TEAM ANALYSIS REQUEST:\n\nDocument: ' + (body.filename || 'uploaded document') + '\n\nContent:\n' + body.rfp_text.substring(0, 50000) : '') + (body.message || '');

  var history = Array.isArray(body.history) ? body.history : [];
  var messages = history.length > 0 ? history : [{ role: 'user', content: userContent }];
  if (history.length > 0 && userContent) {
    messages = history;
  }

  return JSON.stringify({
    model: 'claude-sonnet-4-20250514',
    max_tokens: 4096,
    system: systemPrompt,
    messages: messages
  });
})() }}

