const data = $input.first().json;
let reply = '';
if (data.content && data.content[0]) {
  reply = data.content[0].text || '';
} else if (data.error) {
  reply = 'API Error: ' + (data.error.message || JSON.stringify(data.error));
} else {
  reply = JSON.stringify(data);
}
return [{ json: { reply } }];
